// @ts-check
/** @typedef {import('../../InvocationContext.js').InvocationContext} InvocationContext */

import { Command } from '../../../utils/Command.js'
import { CommandType } from '../../../utils/CommandType.js'
import { RuntimeName } from '../../../utils/RuntimeName.js'
import { handleResultWithAction } from './TypeParsingUtils.js'

/**
 * @param {InvocationContext} invocationContext
 * @returns {Date}
 */
export function parseInstant(invocationContext) {
    const result = invocationContext.invokeInstanceMethod('toEpochMilli').execute()
    return handleResultWithAction(result, (/** @type {any} */ epochMilli) => {
        if (epochMilli == null) throw new Error('toEpochMilli returned null')
        return new Date(Number(epochMilli))
    })
}

/**
 * @param {InvocationContext} invocationContext
 * @returns {Promise<Date>}
 */
export async function parseOffsetDateTime(invocationContext) {
    const instantIc = await invocationContext.invokeInstanceMethod('toInstant').execute()
    const result = instantIc.invokeInstanceMethod('toEpochMilli').execute()
    return handleResultWithAction(result, (/** @type {any} */ epochMilli) => {
        if (epochMilli == null) throw new Error('toEpochMilli returned null')
        return new Date(Number(epochMilli))
    })
}

/**
 * @param {InvocationContext} invocationContext
 * @returns {string}
 */
export function parseUUID(invocationContext) {
    const result = invocationContext.invokeInstanceMethod('toString').execute()
    return handleResultWithAction(result, (/** @type {any} */ val) => String(val))
}

/** Inbound: JVM result type string → JavaScript object */
export const JavaTypeParsingFunctions = new Map(/** @type {[string, (invocationContext: InvocationContext) => unknown][]} */ ([
    ['java.time.Instant', parseInstant],
    ['java.time.OffsetDateTime', parseOffsetDateTime],
    ['java.util.UUID', parseUUID],
]))

/**
 * Outbound: JavaScript object → Command graph targeting the JVM runtime
 * @type {Map<Function, (value: any) => Command>}
 */
export const JavaParsingArgument = new Map([
    [Date, (/** @type {Date} */ value) => new Command(RuntimeName.Jvm, CommandType.InvokeStaticMethod, [
        new Command(RuntimeName.Jvm, CommandType.GetType, ['java.time.Instant']),
        'ofEpochMilli',
        value.getTime(),
    ])],
])
